// Health Tech Nerds Job Parser with CX Leadership Filter
// v1.1: Fixed n8n JSON array handling

const input = $input.all();

// Keywords for customer support/success roles
const SUPPORT_SUCCESS_KEYWORDS = [
  'support', 'success', 'customer', 'client', 'cx', 'experience',
  'service', 'care', 'advocate', 'engagement'
];

// Keywords for leadership roles
const LEADERSHIP_KEYWORDS = [
  'manager', 'director', 'vp', 'vice president', 'head',
  'lead', 'chief', 'supervisor', 'team lead', 'principal',
  'senior manager', 'sr manager', 'associate director', 'sr. director'
];

function normalizeText(text) {
  return (text || '').toLowerCase().trim();
}

function isCXLeadershipRole(title) {
  const normalizedTitle = normalizeText(title);

  const hasSupportSuccess = SUPPORT_SUCCESS_KEYWORDS.some(kw => 
    normalizedTitle.includes(kw)
  );

  const hasLeadership = LEADERSHIP_KEYWORDS.some(kw => 
    normalizedTitle.includes(kw)
  );

  return hasSupportSuccess && hasLeadership;
}

// Flatten all jobs from input
// Health Tech Nerds wraps jobs in { job_postings: [...] }
let allJobs = [];

for (const item of input) {
  if (Array.isArray(item.json)) {
    allJobs = allJobs.concat(item.json);
  } else if (item.json && typeof item.json === 'object') {
    // Check for job_postings wrapper (Health Tech Nerds structure)
    if (item.json.job_postings && Array.isArray(item.json.job_postings)) {
      allJobs = allJobs.concat(item.json.job_postings);
    } else if (item.json.data && Array.isArray(item.json.data)) {
      allJobs = allJobs.concat(item.json.data);
    } else if (item.json.job_data) {
      allJobs.push(item.json);
    }
  }
}

console.log(`Total jobs in feed: ${allJobs.length}`);

const parsedJobs = [];
const allTitles = [];

for (const job of allJobs) {
  if (!job || !job.job_data) continue;

  const jobData = job.job_data;
  const title = jobData.job_title || '';
  allTitles.push(title);

  // Filter for CX leadership roles
  if (!isCXLeadershipRole(title)) continue;

  // Skip Slack-only postings (no real job URL)
  const jobUrl = job.job_url || '';
  if (jobUrl.includes('slack.com/archives')) continue;

  // Build job object matching Job Evaluation Pipeline input format
  parsedJobs.push({
    title: title,
    company: jobData.company_name || 'Unknown',
    location: jobData.location || jobData.location_type || 'Remote',
    salary: jobData.salary || '',
    url: jobUrl,
    source: 'Health Tech Nerds',
    description: jobData.job_description || '',
    company_description: jobData.company_description || '',
    function: jobData.function || '',
    experience_level: jobData.experience_level || '',
    role_type: jobData.role_type || 'Full-time',
    keywords: jobData.keywords_list || '',
    job_id: `htn:${normalizeText(jobData.company_name)}:${normalizeText(title)}`.replace(/[^a-z0-9:]/g, '-')
  });
}

// Debug: show sample titles
console.log(`Sample titles: ${allTitles.slice(0, 5).join(', ')}`);
console.log(`Found ${parsedJobs.length} CX leadership roles from Health Tech Nerds`);

if (parsedJobs.length === 0) {
  return [{ json: { _noJobs: true, message: 'No CX leadership jobs found', totalInFeed: allJobs.length, sampleTitles: allTitles.slice(0, 10) } }];
}

return parsedJobs.map(job => ({ json: job }));

// Dedup against existing Airtable records

const newJobs = $('Parse & Filter CX Roles').all();
const existingJobs = $('Search Existing Jobs').all();

// Build lookup set from existing jobs
const existingKeys = new Set();
for (const existing of existingJobs) {
  const company = (existing.json.Company || '').toLowerCase().trim();
  const title = (existing.json['Job Title'] || '').toLowerCase().trim();
  const url = (existing.json['Job URL'] || '').toLowerCase().trim();

  // Key by URL (most reliable)
  if (url) existingKeys.add(url);

  // Also key by company+title combo
  if (company && title) {
    existingKeys.add(`${company}:${title}`);
  }
}

console.log(`Existing jobs in Airtable: ${existingKeys.size}`);

// Filter out duplicates
const uniqueJobs = [];
for (const job of newJobs) {
  if (job.json._noJobs) continue;

  const url = (job.json.url || '').toLowerCase().trim();
  const company = (job.json.company || '').toLowerCase().trim();
  const title = (job.json.title || '').toLowerCase().trim();
  const companyTitleKey = `${company}:${title}`;

  if (existingKeys.has(url) || existingKeys.has(companyTitleKey)) {
    console.log(`Skipping duplicate: ${job.json.company} - ${job.json.title}`);
    continue;
  }

  uniqueJobs.push(job);
}

console.log(`New jobs to evaluate: ${uniqueJobs.length}`);

if (uniqueJobs.length === 0) {
  return [{ json: { _noJobs: true, message: 'All jobs already in Airtable' } }];
}

return uniqueJobs;

// Map fields for Job Evaluation Pipeline v6.1

const jobs = $input.all();
const mappedJobs = [];

for (const job of jobs) {
  if (job.json._noJobs) continue;

  mappedJobs.push({
    json: {
      'Job Title': job.json.title,
      'Company': job.json.company,
      'Location': job.json.location,
      'Salary Info': job.json.salary,
      'Job URL': job.json.url,
      'Source': 'Health Tech Nerds',
      'Job ID': job.json.job_id,
      'Date Found': new Date().toISOString().split('T')[0],
      // Extra context for evaluation
      '_description': job.json.description,
      '_company_description': job.json.company_description,
      '_function': job.json.function,
      '_experience': job.json.experience_level,
      '_keywords': job.json.keywords
    }
  });
}

console.log(`Mapped ${mappedJobs.length} jobs for evaluation`);

return mappedJobs;
